import math


def simulator(x: float, fidelity: str) -> dict[str, object]:
    if not -3.0 <= x <= 3.0:
        raise ValueError("x is outside the design domain")
    cost = {"low": 1.0, "high": 12.0}[fidelity]
    if x > 2.4:
        return {"status": "failed", "fidelity": fidelity, "cost": cost, "value": None}
    if fidelity == "high" and x < -2.2:
        return {"status": "censored", "fidelity": fidelity, "cost": cost, "value": None}
    high = 0.16 * (x - 1.7) ** 2 + 0.45 * math.sin(2.2 * x) + 0.12 * math.sin(5.3 * x)
    bias = 0.18 * math.sin(1.4 * x + 0.3) if fidelity == "low" else 0.0
    deterministic_noise = 0.03 * math.sin(7.0 * x) if fidelity == "low" else 0.01 * math.sin(7.0 * x)
    return {"status": "ok", "fidelity": fidelity, "cost": cost, "value": high + bias + deterministic_noise}


print(simulator(0.5, "low"))
print(simulator(0.5, "high"))

import numpy as np

def loss_proxy(q: np.ndarray) -> float:
    r, curvature, shift = q
    return float((r - 1.45) ** 2 + 0.4 * curvature**2 + 0.2 * shift**2 + 0.05 * (r - 1.0) ** 2)

q = np.array([1.15, 0.0, 0.0])
print(loss_proxy(q))
